   1→//! Automatic mock generation for external dependencies.
   2→//!
   3→//! Classifies external dependencies into categories (I/O, library, utility)
   4→//! and generates sensible default [`MockConfig`]s without requiring user
   5→//! configuration. Users can override defaults via `.shatter/config.yaml`.
   6→//!
   7→//! Error variant generation produces [`MockConfig`]s with
   8→//! [`MockBehavior::ThrowError`] to exercise error-handling paths. The
   9→//! [`generate_error_variant`] function dispatches on the dependency's return
  10→//! type and I/O category to produce realistic error shapes (HTTP 4xx/5xx for
  11→//! network mocks, connection errors for DB mocks, ENOENT for FS mocks, etc.).
  12→
  13→use std::collections::HashMap;
  14→
  15→use serde_json::{json, Value};
  16→
  17→use crate::protocol::{DependencyKind, ExternalDependency, MockBehavior, MockConfig};
  18→use crate::scope::{DependencyAction, ScopeMatcher};
  19→use crate::types::TypeInfo;
  20→
  21→/// Probability that an auto-mock should use an error variant instead of a
  22→/// success variant. Applied per-dependency during exploration to exercise
  23→/// error-handling paths.
  24→pub const DEFAULT_ERROR_PROBABILITY: f64 = 0.15;
  25→
  26→/// Category of an external dependency, used to select default mock behavior.
  27→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
  28→pub enum IoCategory {
  29→    /// File system operations (fs, path).
  30→    FileSystem,
  31→    /// Network operations (http, fetch, axios, net).
  32→    Network,
  33→    /// Database operations (pg, mysql, mongodb, redis, prisma, knex).
  34→    Database,
  35→    /// Pure utility functions (lodash, ramda, date-fns) — safe to call.
  36→    PureUtility,
  37→    /// Other external library — use type-aware stub.
  38→    ExternalOther,
  39→}
  40→
  41→/// Known module prefixes for each category.
  42→const FS_MODULES: &[&str] = &[
  43→    "fs", "node:fs", "fs/promises", "node:fs/promises", "path", "node:path",
  44→    // Go stdlib
  45→    "os", "io", "io/ioutil", "bufio",
  46→];
  47→const NETWORK_MODULES: &[&str] = &[
  48→    "http", "https", "node:http", "node:https", "net", "node:net",
  49→    "axios", "node-fetch", "fetch", "got", "superagent", "request",
  50→    "undici",
  51→];
  52→const DB_MODULES: &[&str] = &[
  53→    "pg", "mysql", "mysql2", "mongodb", "redis", "ioredis",
  54→    "prisma", "@prisma/client", "knex", "sequelize", "typeorm",
  55→    "mongoose", "sqlite3", "better-sqlite3", "drizzle-orm",
  56→    "database/sql", "gorm.io/gorm",
  57→];
  58→const PURE_UTILITY_MODULES: &[&str] = &[
  59→    "lodash", "lodash-es", "underscore", "ramda", "date-fns",
  60→    "dayjs", "moment", "validator", "uuid", "nanoid",
  61→    "chalk", "debug", "ms",
  62→    "strings", "strconv", "fmt", "math", "sort",
  63→];
  64→
  65→/// Classify an external dependency into an [`IoCategory`].
  66→pub fn classify_dependency(dep: &ExternalDependency) -> IoCategory {
  67→    let module = dep.source_module.as_str();
  68→
  69→    if FS_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
  70→        return IoCategory::FileSystem;
  71→    }
  72→    if NETWORK_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
  73→        return IoCategory::Network;
  74→    }
  75→    if DB_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
  76→        return IoCategory::Database;
  77→    }
  78→    if PURE_UTILITY_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
  79→        return IoCategory::PureUtility;
  80→    }
  81→
  82→    IoCategory::ExternalOther
  83→}
  84→
  85→/// Generate a default [`MockConfig`] for a dependency based on its category.
  86→pub fn generate_default_mock(dep: &ExternalDependency, category: IoCategory) -> MockConfig {
  87→    match category {
  88→        IoCategory::FileSystem => MockConfig {
  89→            symbol: dep.symbol.clone(),
  90→            return_values: vec![default_for_fs(&dep.symbol)],
  91→            should_track_calls: true,
  92→            default_behavior: MockBehavior::RepeatLast,
  93→        },
  94→        IoCategory::Network => MockConfig {
  95→            symbol: dep.symbol.clone(),
  96→            return_values: vec![json!({"status": 200, "data": {}})],
  97→            should_track_calls: true,
  98→            default_behavior: MockBehavior::RepeatLast,
  99→        },
 100→        IoCategory::Database => MockConfig {
 101→            symbol: dep.symbol.clone(),
 102→            return_values: vec![default_for_db(&dep.symbol)],
 103→            should_track_calls: true,
 104→            default_behavior: MockBehavior::RepeatLast,
 105→        },
 106→        IoCategory::PureUtility => MockConfig {
 107→            symbol: dep.symbol.clone(),
 108→            return_values: vec![],
 109→            should_track_calls: false,
 110→            default_behavior: MockBehavior::Passthrough,
 111→        },
 112→        IoCategory::ExternalOther => MockConfig {
 113→            symbol: dep.symbol.clone(),
 114→            return_values: vec![default_for_type(&dep.return_type)],
 115→            should_track_calls: true,
 116→            default_behavior: MockBehavior::RepeatLast,
 117→        },
 118→    }
 119→}
 120→
 121→/// Pick a sensible default for a file-system operation based on the symbol name.
 122→fn default_for_fs(symbol: &str) -> Value {
 123→    let lower = symbol.to_lowercase();
 124→    if lower.contains("read") {
 125→        json!("")
 126→    } else if lower.contains("stat") || lower.contains("lstat") {
 127→        json!({"size": 0, "isFile": true, "isDirectory": false})
 128→    } else if lower.contains("exists") {
 129→        json!(true)
 130→    } else if lower.contains("readdir") || lower.contains("glob") {
 131→        json!([])
 132→    } else {
 133→        // write, mkdir, unlink, etc. — return undefined/null (success)
 134→        Value::Null
 135→    }
 136→}
 137→
 138→/// Pick a sensible default for a database operation based on the symbol name.
 139→fn default_for_db(symbol: &str) -> Value {
 140→    let lower = symbol.to_lowercase();
 141→    if lower.contains("query") || lower.contains("find") || lower.contains("select") || lower.contains("all") {
 142→        json!({"rows": []})
 143→    } else if lower.contains("insert") || lower.contains("create") || lower.contains("save") {
 144→        json!({"rowCount": 1})
 145→    } else if lower.contains("update") || lower.contains("delete") || lower.contains("remove") {
 146→        json!({"rowCount": 0})
 147→    } else {
 148→        Value::Null
 149→    }
 150→}
 151→
 152→/// Generate a type-appropriate default value from TypeInfo.
 153→fn default_for_type(typ: &TypeInfo) -> Value {
 154→    match typ {
 155→        TypeInfo::Int => json!(0),
 156→        TypeInfo::Float => json!(0.0),
 157→        TypeInfo::Str => json!(""),
 158→        TypeInfo::Bool => json!(false),
 159→        TypeInfo::Array { .. } => json!([]),
 160→        TypeInfo::Object { fields } => {
 161→            let mut obj = serde_json::Map::new();
 162→            for (name, field_type) in fields {
 163→                obj.insert(name.clone(), default_for_type(field_type));
 164→            }
 165→            Value::Object(obj)
 166→        }
 167→        TypeInfo::Nullable { .. } => Value::Null,
 168→        TypeInfo::Union { variants } => {
 169→            if let Some(first) = variants.first() {
 170→                default_for_type(first)
 171→            } else {
 172→                Value::Null
 173→            }
 174→        }
 175→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Value::Null,
 176→    }
 177→}
 178→
 179→/// User-provided mock override from `.shatter/config.yaml`.
 180→#[derive(Debug, Clone, PartialEq, serde::Deserialize, serde::Serialize)]
 181→pub struct MockOverride {
 182→    /// Pre-configured return values, replacing auto-generated defaults.
 183→    #[serde(default)]
 184→    pub return_values: Option<Vec<Value>>,
 185→    /// Override the default behavior.
 186→    #[serde(default)]
 187→    pub behavior: Option<MockBehavior>,
 188→}
 189→
 190→/// Generate auto-mocks for all dependencies of a function.
 191→///
 192→/// Returns mock configs for dependencies that:
 193→/// 1. Are not already covered by `existing_mocks` (e.g., behavior-map mocks)
 194→/// 2. Are classified as Mock (not Passthrough or Analyze) by the scope matcher
 195→///
 196→/// User overrides from config take precedence over auto-generated defaults.
 197→pub fn generate_auto_mocks(
 198→    deps: &[ExternalDependency],
 199→    scope: Option<&ScopeMatcher>,
 200→    overrides: &HashMap<String, MockOverride>,
 201→    existing_mocks: &[MockConfig],
 202→) -> Vec<MockConfig> {
 203→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
 204→        .iter()
 205→        .map(|m| m.symbol.as_str())
 206→        .collect();
 207→
 208→    let mut result = Vec::new();
 209→
 210→    for dep in deps {
 211→        // Skip if already covered by a behavior-map mock
 212→        if already_mocked.contains(dep.symbol.as_str()) {
 213→            continue;
 214→        }
 215→
 216→        // Check scope: if Passthrough, skip; if Analyze (no rule), use category logic
 217→        if let Some(matcher) = scope {
 218→            match matcher.classify_dependency(&dep.symbol) {
 219→                DependencyAction::Passthrough => continue,
 220→                DependencyAction::Mock | DependencyAction::Analyze => {}
 221→            }
 222→        }
 223→
 224→        let category = classify_dependency(dep);
 225→
 226→        // Pure utilities default to passthrough — skip generating a mock
 227→        if category == IoCategory::PureUtility && !overrides.contains_key(&dep.symbol) {
 228→            continue;
 229→        }
 230→
 231→        let mut mock = generate_default_mock(dep, category);
 232→
 233→        // Apply user overrides
 234→        if let Some(ov) = overrides.get(&dep.symbol) {
 235→            if let Some(ref vals) = ov.return_values {
 236→                mock.return_values = vals.clone();
 237→            }
 238→            if let Some(ref behavior) = ov.behavior {
 239→                mock.default_behavior = behavior.clone();
 240→            }
 241→        }
 242→
 243→        result.push(mock);
 244→    }
 245→
 246→    result
 247→}
