 249→// ---------------------------------------------------------------------------
 250→// Error variant generation
 251→// ---------------------------------------------------------------------------
 252→
 253→/// Generate a [`MockConfig`] that throws an error, producing a realistic
 254→/// error shape based on the dependency's return type and I/O category.
 255→///
 256→/// Dispatch order:
 257→/// 1. Object with a `"status"` field → HTTP 400/500 error objects
 258→/// 2. Nullable → `null` (represents a "not found" / absent value)
 259→/// 3. Category-aware: Network → HTTP error, Database → connection error,
 260→///    FileSystem → ENOENT
 261→/// 4. Fallback → `ThrowError` behavior with an empty return_values vec
 262→pub fn generate_error_variant(dep: &ExternalDependency, category: IoCategory) -> MockConfig {
 263→    // Check for object with "status" field → HTTP error responses
 264→    if let TypeInfo::Object { fields } = &dep.return_type
 265→        && fields.iter().any(|(name, _)| name == "status")
 266→    {
 267→        return MockConfig {
 268→            symbol: dep.symbol.clone(),
 269→            return_values: vec![
 270→                json!({"status": 400, "error": "Bad Request"}),
 271→                json!({"status": 500, "error": "Internal Server Error"}),
 272→            ],
 273→            should_track_calls: true,
 274→            default_behavior: MockBehavior::RepeatLast,
 275→        };
 276→    }
 277→
 278→    // Nullable → null (represents absence / not-found)
 279→    if matches!(&dep.return_type, TypeInfo::Nullable { .. }) {
 280→        return MockConfig {
 281→            symbol: dep.symbol.clone(),
 282→            return_values: vec![Value::Null],
 283→            should_track_calls: true,
 284→            default_behavior: MockBehavior::RepeatLast,
 285→        };
 286→    }
 287→
 288→    // Category-aware error shapes
 289→    match category {
 290→        IoCategory::Network => MockConfig {
 291→            symbol: dep.symbol.clone(),
 292→            return_values: vec![
 293→                json!({"status": 500, "error": "Internal Server Error"}),
 294→                json!({"status": 503, "error": "Service Unavailable"}),
 295→            ],
 296→            should_track_calls: true,
 297→            default_behavior: MockBehavior::ThrowError,
 298→        },
 299→        IoCategory::Database => MockConfig {
 300→            symbol: dep.symbol.clone(),
 301→            return_values: vec![
 302→                json!({"code": "ECONNREFUSED", "message": "Connection refused"}),
 303→            ],
 304→            should_track_calls: true,
 305→            default_behavior: MockBehavior::ThrowError,
 306→        },
 307→        IoCategory::FileSystem => MockConfig {
 308→            symbol: dep.symbol.clone(),
 309→            return_values: vec![
 310→                json!({"code": "ENOENT", "message": "No such file or directory"}),
 311→            ],
 312→            should_track_calls: true,
 313→            default_behavior: MockBehavior::ThrowError,
 314→        },
 315→        // Fallback: bare ThrowError with no pre-configured return values
 316→        IoCategory::PureUtility | IoCategory::ExternalOther => MockConfig {
 317→            symbol: dep.symbol.clone(),
 318→            return_values: vec![],
 319→            should_track_calls: true,
 320→            default_behavior: MockBehavior::ThrowError,
 321→        },
 322→    }
 323→}
 324→
 325→/// Generate error-variant [`MockConfig`]s for dependencies that should
 326→/// exercise error-handling paths.
 327→///
 328→/// Uses `error_probability` to decide per-dependency whether to generate an
 329→/// error mock. Dependencies already covered by `existing_mocks` or marked
 330→/// as passthrough are skipped. Pure utilities are always skipped.
 331→pub fn generate_error_mocks(
 332→    deps: &[ExternalDependency],
 333→    scope: Option<&ScopeMatcher>,
 334→    existing_mocks: &[MockConfig],
 335→    error_probability: f64,
 336→    rng: &mut impl rand::Rng,
 337→) -> Vec<MockConfig> {
 338→    let already_mocked: std::collections::HashSet<&str> = existing_mocks
 339→        .iter()
 340→        .map(|m| m.symbol.as_str())
 341→        .collect();
 342→
 343→    let mut result = Vec::new();
 344→
 345→    for dep in deps {
 346→        if already_mocked.contains(dep.symbol.as_str()) {
 347→            continue;
 348→        }
 349→
 350→        if let Some(matcher) = scope
 351→            && matches!(
 352→                matcher.classify_dependency(&dep.symbol),
 353→                DependencyAction::Passthrough
 354→            )
 355→        {
 356→            continue;
 357→        }
 358→
 359→        let category = classify_dependency(dep);
 360→        if category == IoCategory::PureUtility {
 361→            continue;
 362→        }
 363→
 364→        if rng.random_bool(error_probability.clamp(0.0, 1.0)) {
 365→            result.push(generate_error_variant(dep, category));
 366→        }
 367→    }
 368→
 369→    result
 370→}
