 675→        let mocks = generate_auto_mocks(&deps, None, &overrides, &[]);
 676→
 677→        // 4 mocks generated: fs, network, db (overridden), and external other.
 678→        // lodash (pure utility) is skipped.
 679→        assert_eq!(mocks.len(), 4, "expected 4 mocks (lodash skipped)");
 680→
 681→        let by_symbol: HashMap<&str, &MockConfig> =
 682→            mocks.iter().map(|m| (m.symbol.as_str(), m)).collect();
 683→
 684→        // fs.readFileSync → filesystem category, returns ""
 685→        let fs_mock = by_symbol["readFileSync"];
