 693→        assert!(net_mock.should_track_calls);
 694→
 695→        // pg.query → database category, but overridden with custom rows
 696→        let db_mock = by_symbol["query"];
 697→        assert_eq!(
 698→            db_mock.return_values,
 699→            vec![json!({"rows": [{"id": 1, "name": "alice"}]})]
 700→        );
 701→        assert!(db_mock.should_track_calls);
 702→
 703→        // my-analytics-lib.compute → external other, type-aware default for Int
 704→        let ext_mock = by_symbol["compute"];
 705→        assert_eq!(ext_mock.return_values, vec![json!(0)]);
 706→        assert!(ext_mock.should_track_calls);
 707→
 708→        // Verify lodash.map is NOT in the mock list
 709→        assert!(!by_symbol.contains_key("map"));
 710→    }
